1	const PROCESSING_FEE = 5;
2	const FIRST_INSURANCE_RATE = 0.1;
3	
4	const BASE_PREMIUMS: Record<string, number> = {
5	  sword: 100,
6	  amulet: 60,
7	  staff: 80,
8	  potion: 40,
9	  rune: 25,
10	  moonstone: 25,
11	};
12	
13	type Item = { type: string };
14	
15	type Scenario = {
16	  customer: { yearsWithMHPCO: number };
17	  steps: Array<{ op: "quote"; items: Item[] }>;
18	};
19	
20	type QuoteResult = { premium: number };
21	
22	const COMPONENT_BLOCK_SIZE = 3;
23	const COMPONENT_BLOCK_PREMIUM = 60;
24	
25	const isRuneBlock = (items: Item[]): boolean =>
26	  items.length === COMPONENT_BLOCK_SIZE && items.every((item) => item.type === "rune");
27	
28	const sumOfBasePremiums = (items: Item[]): number =>
29	  items.reduce((sum, item) => sum + BASE_PREMIUMS[item.type], 0);
30	
31	const basePremiumFor = (items: Item[]): number =>
32	  isRuneBlock(items) ? COMPONENT_BLOCK_PREMIUM : sumOfBasePremiums(items);
33	
34	const quotePremium = (items: Item[]): QuoteResult => {
35	  const base = basePremiumFor(items);
36	  return { premium: Math.ceil(base + base * FIRST_INSURANCE_RATE + PROCESSING_FEE) };
37	};
38	
39	export const processScenario = (scenario: Scenario): { results: QuoteResult[] } => {
40	  const results = scenario.steps.map((step) => quotePremium(step.items));
41	  return { results };
42	};
